		await applyPluginContextMenuAction(
			{
				pluginId: 'test.plugin',
				index: 0,
				targetId: 'missing.ts',
				targetType: 'node',
			},
			{
				getPluginApi: () => ({ contextMenuItems: [{ action }] }),
