    expect(rebuildGraphData).toHaveBeenCalledOnce();
  });

  it('smart rebuild ignores a self-installed rebuild implementation', () => {
    const rebuildGraphData = vi.fn();
    const smartRebuildGraphData = vi.fn((_nextSource, _id, handlers: {
      rebuildAndSend(): void;
    }) => {
