describe('graphView/mergedGroups', () => {
  it('keeps user groups ahead of built-in and plugin defaults', () => {
    const groups = buildGraphViewMergedGroups(
      [{ id: 'user:src', pattern: 'src/**', color: '#ff0000' }],
      [{ id: 'default:*.json', pattern: '*.json', color: '#F9C74F' }],
      [
        {
          id: 'plugin:codegraphy.typescript:*.ts',
          pattern: '*.ts',
          color: '#3178C6',
        },
        {
          id: 'plugin:codegraphy.python:*.py',
          pattern: '*.py',
          color: '#3776AB',
        },
      ],
    );

    expect(groups).toEqual([
      { id: 'user:src', pattern: 'src/**', color: '#ff0000' },
      { id: 'default:*.json', pattern: '*.json', color: '#F9C74F' },
      { id: 'plugin:codegraphy.typescript:*.ts', pattern: '*.ts', color: '#3178C6' },
      { id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' },
    ]);
  });

  it('keeps plain ids untouched', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [{ id: 'plain', pattern: 'plain', color: '#123456' }],
      [],
    );

    expect(groups).toEqual([{ id: 'plain', pattern: 'plain', color: '#123456' }]);
  });

  it('does not infer a disabled empty section key from leading-colon ids', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [],
      [{ id: ':leading', pattern: ':leading', color: '#654321' }],
    );

    expect(groups).toEqual([{ id: ':leading', pattern: ':leading', color: '#654321' }]);
  });

  it('includes built-in and plugin defaults when no user groups exist', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [{ id: 'default:*.json', pattern: '*.json', color: '#F9C74F' }],
      [{ id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' }],
    );

    expect(groups).toEqual([
      { id: 'default:*.json', pattern: '*.json', color: '#F9C74F' },
      { id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' },
    ]);
  });

  it('applies persisted visibility overrides to built-in and plugin defaults', () => {
    const groups = buildGraphViewMergedGroups(
      [],
      [{ id: 'default:*.json', pattern: '*.json', color: '#F9C74F' }],
      [{ id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB' }],
      {
        'default:*.json': false,
        'plugin:codegraphy.python:*.py': true,
      },
    );

    expect(groups).toEqual([
      { id: 'default:*.json', pattern: '*.json', color: '#F9C74F', disabled: true },
      { id: 'plugin:codegraphy.python:*.py', pattern: '*.py', color: '#3776AB', disabled: false },
    ]);
  });

  it('keeps unordered groups stable while moving ordered groups ahead of them', () => {
    const groups = buildGraphViewMergedGroups(
      [{ id: 'user:keep-first', pattern: 'src/**', color: '#111111' }],
      [
        { id: 'ordered', pattern: '*.ts', color: '#222222' },
        { id: 'default:keep-stable', pattern: '*.json', color: '#333333' },
      ],
      [{ id: 'plugin:keep-stable', pattern: '*.py', color: '#444444' }],
      {},
      ['ordered'],
    );

    expect(groups.map((group) => group.id)).toEqual([
      'ordered',
      'user:keep-first',
      'default:keep-stable',
      'plugin:keep-stable',
    ]);
  });

  it('preserves relative order when legend order does not mention either group', () => {
    const groups = buildGraphViewMergedGroups(
      [{ id: 'user:a', pattern: 'a/**', color: '#111111' }],
      [{ id: 'user:b', pattern: 'b/**', color: '#222222' }],
      [],
      {},
      ['ordered-only'],
    );

    expect(groups.map((group) => group.id)).toEqual(['user:a', 'user:b']);
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  refreshGraphViewRawData,
  refreshIncrementalGraphViewRawData,
} from '../../../../../src/extension/graphView/analysis/execution/refresh';
import {
  createExecutionAnalyzer,
  createExecutionState,
} from './fixtures';
import { EMPTY_GRAPH_DATA } from '../../../../../src/extension/graphView/analysis/execution/publish';

describe('graph view analysis execution refresh', () => {
  it('runs explicit full refresh through the analyzer refresh path', async () => {
    const refreshIndex = vi.fn(async () => ({ nodes: [], edges: [] }));
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshIndex,
      }),
      analyzerInitialized: true,
    });

    await refreshGraphViewRawData(new AbortController().signal, state, vi.fn());

    expect(refreshIndex).toHaveBeenCalledOnce();
    expect(analyze).not.toHaveBeenCalled();
  });

  it('falls back to analyzer analyze for full refreshes when refreshIndex is unavailable', async () => {
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshIndex: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual({ nodes: [], edges: [] });
    expect(analyze).toHaveBeenCalledOnce();
  });

  it('runs scoped incremental refresh through the changed-file analyzer path', async () => {
    const refreshChangedFiles = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'incremental',
      changedFilePaths: ['src/index.ts'],
      analyzer: createExecutionAnalyzer({
        refreshChangedFiles,
      }),
      analyzerInitialized: true,
    });

    await refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn());

    expect(refreshChangedFiles).toHaveBeenCalledWith(
      ['src/index.ts'],
      [],
      new Set<string>(),
      expect.any(AbortSignal),
      expect.any(Function),
    );
  });

  it('falls back to analyzer analyze when incremental refresh support is unavailable', async () => {
    const analyzeResult = { nodes: [], edges: [] };
    const analyze = vi.fn(async () => analyzeResult);
    const state = createExecutionState({
      mode: 'incremental',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshChangedFiles: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual(analyzeResult);

    expect(analyze).toHaveBeenCalledOnce();
  });

  it('uses empty changed-file paths for incremental refreshes and falls back to the empty graph', async () => {
    const refreshChangedFiles = vi.fn(async () => undefined as never);
    const state = createExecutionState({
      mode: 'incremental',
      changedFilePaths: undefined,
      analyzer: createExecutionAnalyzer({
        refreshChangedFiles,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual(EMPTY_GRAPH_DATA);
    expect(refreshChangedFiles).toHaveBeenCalledWith(
      [],
      [],
      new Set<string>(),
      expect.any(AbortSignal),
      expect.any(Function),
    );
  });

  it('falls back to the empty graph when no refresh or analyze path is available', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze: undefined,
        refreshIndex: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });

  it('falls back to the empty graph when no analyzer exists for a full refresh', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: undefined,
      analyzerInitialized: false,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });

  it('falls back to the empty graph when no analyzer exists for an incremental refresh', async () => {
    const state = createExecutionState({
      mode: 'incremental',
      analyzer: undefined,
      analyzerInitialized: false,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });
});

