        'git:/workspace/src/app.ts?%7B%22path%22:%22/workspace/src/app.ts%22,%22ref%22:%22abc123%22%7D',
    } as vscode.Uri;
    const parse = vi.fn(() => gitUri);
    (vscode.Uri as unknown as Record<string, unknown>).parse = parse;
