    expect(parse).toHaveBeenCalledWith(
      'git:/workspace/src/app.ts?{"path":"/workspace/src/app.ts","ref":"abc123"}',
    );
    expect(openTextDocument).toHaveBeenCalledWith(gitUri);
    expect(showTextDocument).toHaveBeenCalledWith(document, {
      preview: true,
      preserveFocus: false,
    });
