      _extensionUri: vscode.Uri.file('/test/extension'),
      _view: undefined,
      _timelineView: undefined,
      _panels: [existingPanel],
      _getLocalResourceRoots: vi.fn(() => [vscode.Uri.file('/test/root')]),
