import { describe, expect, it, vi } from 'vitest';
import { runGraphViewTimelineIndex } from '../../../../../src/extension/graphView/timeline/indexing/run';

describe('graph view timeline execution', () => {
  it('indexes commit history, sends progress, and applies the resulting timeline state', async () => {
    const state = {
      gitAnalyzer: {
        indexHistory: vi.fn(async (onProgress, _signal, maxCommits) => {
          onProgress('scan', 1, maxCommits);
          return [
            { sha: '111', timestamp: 1, message: 'one', author: 'A', parents: [] },
            { sha: '222', timestamp: 2, message: 'two', author: 'B', parents: ['111'] },
          ];
        }),
      },
      indexingController: new AbortController(),
    };
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn((error: unknown) => String(error)),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(state, handlers);

    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'INDEX_PROGRESS',
      payload: { phase: 'scan', current: 1, total: 500 },
    });
    expect(handlers.sendMessage).toHaveBeenCalledWith({
      type: 'TIMELINE_DATA',
      payload: {
        commits: [
          { sha: '111', timestamp: 1, message: 'one', author: 'A', parents: [] },
          { sha: '222', timestamp: 2, message: 'two', author: 'B', parents: ['111'] },
        ],
        currentSha: '222',
      },
    });
    expect(handlers.jumpToCommit).toHaveBeenCalledWith('222');
  });

  it('shows the no-commits message when indexing returns no commits', async () => {
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn((error: unknown) => String(error)),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(
      {
        gitAnalyzer: {
          indexHistory: vi.fn(async () => []),
        },
        indexingController: new AbortController(),
      },
      handlers,
    );

    expect(handlers.showInformationMessage).toHaveBeenCalledWith('No commits found to index');
    expect(handlers.jumpToCommit).not.toHaveBeenCalled();
  });

  it('reports non-abort indexing failures and invalidates the cache', async () => {
    const error = new Error('kaboom');
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn(() => 'kaboom'),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(
      {
        gitAnalyzer: {
          indexHistory: vi.fn(async () => {
            throw error;
          }),
        },
        indexingController: new AbortController(),
      },
      handlers,
    );

    expect(handlers.logError).toHaveBeenCalledWith('[CodeGraphy] Indexing failed:', error);
    expect(handlers.showErrorMessage).toHaveBeenCalledWith('Timeline indexing failed: kaboom');
    expect(handlers.sendMessage).toHaveBeenCalledWith({ type: 'CACHE_INVALIDATED' });
  });

  it('returns quietly for abort failures', async () => {
    const error = new Error('aborted');
    error.name = 'AbortError';
    const handlers = {
      getMaxCommits: vi.fn(() => 500),
      sendMessage: vi.fn(),
      showInformationMessage: vi.fn(),
      showErrorMessage: vi.fn(),
      toErrorMessage: vi.fn(() => 'aborted'),
      jumpToCommit: vi.fn(async () => undefined),
      logError: vi.fn(),
    };

    await runGraphViewTimelineIndex(
      {
        gitAnalyzer: {
          indexHistory: vi.fn(async () => {
            throw error;
          }),
        },
        indexingController: new AbortController(),
      },
      handlers,
    );

    expect(handlers.logError).not.toHaveBeenCalled();
    expect(handlers.showErrorMessage).not.toHaveBeenCalled();
    expect(handlers.sendMessage).not.toHaveBeenCalledWith({ type: 'CACHE_INVALIDATED' });
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  prepareGraphViewTimelineIndex,
  type GraphViewTimelineIndexSetupHandlers,
  type GraphViewTimelineIndexSetupState,
} from '../../../../../src/extension/graphView/timeline/indexing/setup';

function createState(
  overrides: Partial<GraphViewTimelineIndexSetupState> = {},
): GraphViewTimelineIndexSetupState {
  return {
    analyzer: undefined,
    analyzerInitialized: false,
    gitAnalyzer: undefined,
    indexingController: undefined,
    filterPatterns: [],
    ...overrides,
  };
}

function createHandlers(
  overrides: Partial<GraphViewTimelineIndexSetupHandlers> = {},
): GraphViewTimelineIndexSetupHandlers {
  return {
    workspaceFolder: undefined,
    verifyGitRepository: vi.fn(() => Promise.resolve()),
    createGitAnalyzer: vi.fn(() => ({
      indexHistory: vi.fn(() => Promise.resolve([])),
    })),
    showErrorMessage: vi.fn(),
    ...overrides,
  };
}

describe('graph view timeline setup', () => {
  it('blocks indexing when no workspace folder is available', async () => {
    const state = createState();
    const handlers = createHandlers();

    const ready = await prepareGraphViewTimelineIndex(state, handlers);

    expect(ready).toBe(false);
    expect(handlers.showErrorMessage).toHaveBeenCalledWith('No workspace folder open');
  });

  it('blocks indexing when the workspace is not a git repository', async () => {
    const state = createState();
    const handlers = createHandlers({
      workspaceFolder: { uri: { fsPath: '/workspace' } },
      verifyGitRepository: vi.fn(() => Promise.reject(new Error('not git'))),
    });

    const ready = await prepareGraphViewTimelineIndex(state, handlers);

    expect(ready).toBe(false);
    expect(handlers.showErrorMessage).toHaveBeenCalledWith(
      'This workspace is not a git repository',
    );
  });

  it('initializes analyzer state and creates the git analyzer once', async () => {
    const analyzer = {
      initialize: vi.fn(() => Promise.resolve()),
      getPluginFilterPatterns: vi.fn(() => ['**/*.generated.ts']),
    };
    const gitAnalyzer = {
      indexHistory: vi.fn(() => Promise.resolve([])),
    };
    const state = createState({
      analyzer,
      filterPatterns: ['src/generated/**'],
    });
    const handlers = createHandlers({
      workspaceFolder: { uri: { fsPath: '/workspace' } },
      createGitAnalyzer: vi.fn(() => gitAnalyzer),
    });

    const ready = await prepareGraphViewTimelineIndex(state, handlers);

    expect(ready).toBe(true);
    expect(analyzer.initialize).toHaveBeenCalledOnce();
    expect(state.analyzerInitialized).toBe(true);
    expect(state.gitAnalyzer).toBe(gitAnalyzer);
    expect(handlers.createGitAnalyzer).toHaveBeenCalledWith('/workspace', [
      '**/node_modules/**',
      '**/dist/**',
      '**/build/**',
      '**/out/**',
      '**/.git/**',
      '**/.codegraphy/**',
      '**/coverage/**',
      '**/*.min.js',
      '**/*.bundle.js',
      '**/*.map',
      '**/*.generated.ts',
      'src/generated/**',
    ]);
    expect(state.indexingController).toBeInstanceOf(AbortController);
  });

  it('returns false after preparing the controller when analyzer state is unavailable', async () => {
    const state = createState();
    const handlers = createHandlers({
      workspaceFolder: { uri: { fsPath: '/workspace' } },
    });

    const ready = await prepareGraphViewTimelineIndex(state, handlers);

    expect(ready).toBe(false);
    expect(state.indexingController).toBeInstanceOf(AbortController);
    expect(handlers.createGitAnalyzer).not.toHaveBeenCalled();
  });

  it('reuses initialized analyzer and existing git analyzer instances', async () => {
    const analyzer = {
      initialize: vi.fn(() => Promise.resolve()),
      getPluginFilterPatterns: vi.fn(() => ['**/*.generated.ts']),
    };
    const existingGitAnalyzer = {
      indexHistory: vi.fn(() => Promise.resolve([])),
    };
    const previousController = new AbortController();
    const abortSpy = vi.spyOn(previousController, 'abort');
    const state = createState({
      analyzer,
      analyzerInitialized: true,
      gitAnalyzer: existingGitAnalyzer,
      indexingController: previousController,
      filterPatterns: ['src/generated/**'],
    });
    const handlers = createHandlers({
      workspaceFolder: { uri: { fsPath: '/workspace' } },
    });

    const ready = await prepareGraphViewTimelineIndex(state, handlers);

    expect(ready).toBe(true);
    expect(abortSpy).toHaveBeenCalledOnce();
    expect(analyzer.initialize).not.toHaveBeenCalled();
    expect(handlers.createGitAnalyzer).not.toHaveBeenCalled();
    expect(state.gitAnalyzer).toBe(existingGitAnalyzer);
    expect(state.indexingController).toBeInstanceOf(AbortController);
    expect(state.indexingController).not.toBe(previousController);
  });
});

import { describe, expect, it, vi } from 'vitest';
