import { describe, expect, it, vi } from 'vitest';
import { applyGraphViewTimelineIndexResult } from '../../../../../src/extension/graphView/timeline/indexing/result';

describe('graph view timeline result', () => {
  it('reports when indexing returns no commits', async () => {
    const sendMessage = vi.fn();
    const showInformationMessage = vi.fn();
    const jumpToCommit = vi.fn(() => Promise.resolve());
    const state = {
      timelineActive: false,
      currentCommitSha: undefined,
    };

    await applyGraphViewTimelineIndexResult([], state, {
      sendMessage,
      showInformationMessage,
      jumpToCommit,
    });

    expect(showInformationMessage).toHaveBeenCalledWith('No commits found to index');
    expect(sendMessage).not.toHaveBeenCalled();
    expect(jumpToCommit).not.toHaveBeenCalled();
  });

  it('publishes timeline data for the latest commit and activates timeline state', async () => {
    const commits = [
      { sha: '111', timestamp: 1, message: 'one', author: 'A', parents: [] },
      { sha: '222', timestamp: 2, message: 'two', author: 'B', parents: ['111'] },
    ];
    const sendMessage = vi.fn();
    const jumpToCommit = vi.fn(() => Promise.resolve());
    const state = {
      timelineActive: false,
      currentCommitSha: undefined as string | undefined,
    };

    await applyGraphViewTimelineIndexResult(commits, state, {
      sendMessage,
      showInformationMessage: vi.fn(),
      jumpToCommit,
    });

    expect(state.timelineActive).toBe(true);
    expect(state.currentCommitSha).toBe('222');
    expect(sendMessage).toHaveBeenCalledWith({
      type: 'TIMELINE_DATA',
      payload: { commits, currentSha: '222' },
    });
    expect(jumpToCommit).toHaveBeenCalledWith('222');
  });

  it('returns without activating timeline state when the latest commit entry is missing', async () => {
    const sendMessage = vi.fn();
    const showInformationMessage = vi.fn();
    const jumpToCommit = vi.fn(() => Promise.resolve());
    const state = {
      timelineActive: false,
      currentCommitSha: undefined as string | undefined,
    };

    await applyGraphViewTimelineIndexResult([
      { sha: '111', timestamp: 1, message: 'one', author: 'A', parents: [] },
      undefined as never,
    ], state, {
      sendMessage,
      showInformationMessage,
      jumpToCommit,
    });

    expect(state.timelineActive).toBe(false);
    expect(state.currentCommitSha).toBeUndefined();
    expect(showInformationMessage).not.toHaveBeenCalled();
    expect(sendMessage).not.toHaveBeenCalled();
    expect(jumpToCommit).not.toHaveBeenCalled();
  });
});

import { describe, expect, it, vi } from 'vitest';
import { applyPluginInteraction } from '../../../../../src/extension/graphView/webview/pluginMessages/interaction';

describe('graph view plugin interaction message', () => {
	it('routes plugin graph interactions to the plugin api', () => {
		const deliverWebviewMessage = vi.fn();

		applyPluginInteraction(
			{ event: 'plugin:test.plugin:ping', data: { ok: true } },
			{
				getPluginApi: () => ({ deliverWebviewMessage }),
				emitEvent: vi.fn(),
			},
		);

		expect(deliverWebviewMessage).toHaveBeenCalledWith({
			type: 'ping',
			data: { ok: true },
		});
	});

	it('preserves nested plugin event names when forwarding to the plugin api', () => {
		const deliverWebviewMessage = vi.fn();

		applyPluginInteraction(
			{ event: 'plugin:test.plugin:graph:event', data: { ok: true } },
			{
				getPluginApi: () => ({ deliverWebviewMessage }),
				emitEvent: vi.fn(),
			},
		);

		expect(deliverWebviewMessage).toHaveBeenCalledWith({
			type: 'graph:event',
			data: { ok: true },
		});
	});

	it('emits non-plugin graph interactions on the event bus', () => {
		const emitEvent = vi.fn();

		applyPluginInteraction(
			{ event: 'graph:nodeClick', data: { nodeId: 'src/app.ts' } },
			{
				getPluginApi: vi.fn(),
				emitEvent,
			},
		);

		expect(emitEvent).toHaveBeenCalledWith('graph:nodeClick', { nodeId: 'src/app.ts' });
	});

	it('ignores malformed plugin graph interactions', () => {
		const emitEvent = vi.fn();
		const getPluginApi = vi.fn();

		applyPluginInteraction(
			{ event: 'plugin:test.plugin', data: { ok: true } },
			{
				getPluginApi,
				emitEvent,
			},
