import { describe, expect, it, vi } from 'vitest';
import type { IGraphControlsSnapshot } from '../../../../src/shared/graphControls/types';
import {
  buildGraphControlsUpdatedMessage,
  sendGraphControlsUpdated,
} from '../../../../src/extension/graphView/controls/send';

describe('extension/graphView/controls/send', () => {
  it('ignores invalid registry node and edge definitions when building the snapshot message', () => {
    const sendMessage = vi.fn();

    sendGraphControlsUpdated(
      {
        nodes: [{ id: 'src/app.ts', label: 'App', color: '#111111', nodeType: 'file' }],
        edges: [{ id: 'src/app.ts->src/lib.ts#import', from: 'src/app.ts', to: 'src/lib.ts', kind: 'import', sources: [] }],
      },
      {
        registry: {
          listNodeTypes: () => [
            null,
            { id: 'route', label: 'Route', defaultColor: '#22C55E', defaultVisible: true },
            { id: 'bad-node', label: 'Bad Node', defaultColor: '#22C55E', defaultVisible: 'yes' },
          ],
          listEdgeTypes: () => [
            undefined,
            { id: 'plugin:route', label: 'Route', defaultColor: '#10B981', defaultVisible: true },
            { id: 'bad-edge', label: 'Bad Edge', defaultColor: '#10B981', defaultVisible: 'yes' },
          ],
        },
      },
      sendMessage,
      { get: <T>(_key: string, defaultValue: T): T => defaultValue },
    );

    expect(sendMessage).toHaveBeenCalledWith(expect.objectContaining({
      type: 'GRAPH_CONTROLS_UPDATED',
      payload: expect.objectContaining({
        nodeTypes: expect.arrayContaining([
          expect.objectContaining({ id: 'route' }),
        ]),
        edgeTypes: expect.arrayContaining([
          expect.objectContaining({ id: 'plugin:route' }),
        ]),
      }),
    }));

    const payload = sendMessage.mock.calls[0][0].payload;
    expect(payload).toBeDefined();
    expect(payload.nodeTypes.some((nodeType: { id: string }) => nodeType.id === 'bad-node')).toBe(false);
    expect(payload.edgeTypes.some((edgeType: { id: string }) => edgeType.id === 'bad-edge')).toBe(false);
  });

  it('treats missing registry methods and non-array results as no plugin definitions', () => {
    const sendMessage = vi.fn();

    sendGraphControlsUpdated(
      {
        nodes: [{ id: 'src/app.ts', label: 'App', color: '#111111', nodeType: 'file' }],
        edges: [{ id: 'src/app.ts->src/lib.ts#import', from: 'src/app.ts', to: 'src/lib.ts', kind: 'import', sources: [] }],
      },
      {
        registry: {
          listNodeTypes: 'not-a-function',
          listEdgeTypes: () => 'not-an-array',
        },
      },
      sendMessage,
      { get: <T>(_key: string, defaultValue: T): T => defaultValue },
    );

    const payload = sendMessage.mock.calls[0][0].payload;
    expect(payload).toBeDefined();
    expect(payload.nodeTypes.map((nodeType: { id: string }) => nodeType.id)).toEqual([
      'file',
      'folder',
      'package',
    ]);
    expect(payload.edgeTypes.some((edgeType: { id: string }) => edgeType.id === 'plugin:route')).toBe(false);
  });

  it('uses only core definitions when the analyzer is absent', () => {
    const sendMessage = vi.fn();

    expect(() =>
      sendGraphControlsUpdated(
        {
          nodes: [{ id: 'src/app.ts', label: 'App', color: '#111111', nodeType: 'file' }],
          edges: [{ id: 'src/app.ts->src/lib.ts#import', from: 'src/app.ts', to: 'src/lib.ts', kind: 'import', sources: [] }],
        },
        undefined,
        sendMessage,
        { get: <T>(_key: string, defaultValue: T): T => defaultValue },
      ),
    ).not.toThrow();

    expect(sendMessage).toHaveBeenCalledOnce();
    expect(sendMessage.mock.calls[0][0].type).toBe('GRAPH_CONTROLS_UPDATED');

    const payload = sendMessage.mock.calls[0][0].payload;
    expect(payload).toBeDefined();
    expect(payload.nodeTypes.map((nodeType: { id: string }) => nodeType.id)).toEqual([
      'file',
      'folder',
      'package',
    ]);
    expect(payload.edgeTypes.some((edgeType: { id: string }) => edgeType.id === 'plugin:route')).toBe(false);
  });

  it('keeps the snapshot payload intact when building the outbound message', () => {
    const snapshot: IGraphControlsSnapshot = {
      nodeTypes: [{ id: 'file', label: 'File', defaultColor: '#A1A1AA', defaultVisible: true }],
      edgeTypes: [{ id: 'import', label: 'Import', defaultColor: '#60A5FA', defaultVisible: true }],
      nodeColors: { file: '#A1A1AA' },
      nodeVisibility: { file: true },
      edgeVisibility: { import: true },
      edgeColors: { import: '#60A5FA' },
    };

    expect(buildGraphControlsUpdatedMessage(snapshot)).toStrictEqual({
      type: 'GRAPH_CONTROLS_UPDATED',
      payload: snapshot,
    });
  });
});

import { describe, expect, it } from 'vitest';
import { STRUCTURAL_NESTS_EDGE_KIND } from '../../../../src/shared/graphControls/defaults';
import { captureGraphControlsSnapshot } from '../../../../src/extension/graphView/controls/send';

describe('extension/graphView/controls/snapshot', () => {
  it('merges core and plugin graph control definitions with stored settings overrides', () => {
    const snapshot = captureGraphControlsSnapshot(
      {
        get: <T>(key: string, defaultValue: T): T => {
          if (key === 'nodeVisibility') {
            return { file: true, folder: true, route: false } as T;
          }
          if (key === 'nodeColors') {
            return { file: '#abcdef', route: '#123456' } as T;
          }
          if (key === 'edgeVisibility') {
            return { import: true, 'plugin:route': false } as T;
          }
          if (key === 'edgeColors') {
            return { import: '#ff00ff', 'plugin:route': '#0f0f0f' } as T;
          }
          return defaultValue;
        },
      },
      {
        nodes: [
          { id: 'src/App.ts', label: 'App', color: '#111111', nodeType: 'file' },
          { id: 'src', label: 'src', color: '#222222', nodeType: 'folder' },
          { id: 'app:route', label: 'Route', color: '#333333', nodeType: 'route' },
        ],
        edges: [
          { id: 'src/App.ts->pkg:docs#import', from: 'src/App.ts', to: 'pkg:docs', kind: 'import', sources: [] },
          { id: 'src->src/App.ts#custom:route', from: 'src', to: 'src/App.ts', kind: 'custom:route', sources: [] },
        ],
      },
      [
        {
          id: 'route',
          label: 'Routes',
          defaultColor: '#22C55E',
          defaultVisible: true,
        },
      ],
      [
        {
          id: 'plugin:route',
          label: 'Route Links',
          defaultColor: '#10B981',
          defaultVisible: true,
        },
      ],
    );

    expect(snapshot.nodeTypes.map(nodeType => nodeType.id)).toEqual(['file', 'folder', 'package', 'route']);
    expect(snapshot.edgeTypes.some(edgeType => edgeType.id === STRUCTURAL_NESTS_EDGE_KIND)).toBe(true);
    expect(snapshot.edgeTypes.some(edgeType => edgeType.id === 'custom:route')).toBe(true);
    expect(snapshot.nodeColors).toEqual({
      file: '#ABCDEF',
      folder: '#A1A1AA',
      package: '#F59E0B',
      route: '#123456',
    });
    expect(snapshot.nodeVisibility).toEqual({ file: true, folder: true, package: false, route: false });
    expect(snapshot.edgeVisibility).toEqual(expect.objectContaining({
      import: true,
      'plugin:route': false,
      [STRUCTURAL_NESTS_EDGE_KIND]: true,
      'custom:route': true,
    }));
    expect(snapshot.edgeColors).toEqual(expect.objectContaining({
      import: '#FF00FF',
      'plugin:route': '#0F0F0F',
      [STRUCTURAL_NESTS_EDGE_KIND]: '#64748B',
    }));
  });

  it('drops invalid visibility and color values while keeping defaults intact', () => {
    const snapshot = captureGraphControlsSnapshot(
      {
        get: <T>(key: string, defaultValue: T): T => {
          if (key === 'nodeVisibility') {
            return { file: true, folder: 'yes' } as T;
          }
          if (key === 'nodeColors') {
            return { file: 'bad-color' } as T;
          }
          if (key === 'edgeColors') {
            return { import: 'bad-color' } as T;
          }
          return defaultValue;
        },
      },
      {
        nodes: [{ id: 'src/App.ts', label: 'App', color: '#111111', nodeType: 'file' }],
        edges: [{ id: 'src/App.ts->pkg:docs#import', from: 'src/App.ts', to: 'pkg:docs', kind: 'import', sources: [] }],
      },
      [],
      [],
    );

    expect(snapshot.nodeColors.file).toBe('#A1A1AA');
    expect(snapshot.nodeVisibility).toEqual({ file: true, folder: false, package: false });
    expect(snapshot.edgeColors.import).toBe('#60A5FA');
    expect(snapshot.edgeColors[STRUCTURAL_NESTS_EDGE_KIND]).toBe('#64748B');
  });
});

